import React from 'react';
import { Link } from 'react-router-dom';

export default function Logo({ size = 'md' }) {
  const s = { sm: [28, 16], md: [36, 20], lg: [44, 24] }[size];
  return (
    <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: 10, textDecoration: 'none', flexShrink: 0 }}>
      <div style={{
        width: s[0], height: s[0], borderRadius: Math.floor(s[0] * .25),
        background: 'linear-gradient(135deg,#0099FF,#FF7A00)',
        display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
      }}>
        <svg viewBox="0 0 32 32" width={s[0] * .6} height={s[0] * .6} fill="none">
          <circle cx="16" cy="16" r="4.5" fill="white" />
          <circle cx="6"  cy="8"  r="2.8" fill="white" opacity=".82" />
          <circle cx="26" cy="8"  r="2.8" fill="white" opacity=".82" />
          <circle cx="6"  cy="24" r="2.8" fill="white" opacity=".82" />
          <circle cx="26" cy="24" r="2.8" fill="white" opacity=".82" />
          <line x1="16" y1="16" x2="6"  y2="8"  stroke="white" strokeWidth="1.6" opacity=".7" />
          <line x1="16" y1="16" x2="26" y2="8"  stroke="white" strokeWidth="1.6" opacity=".7" />
          <line x1="16" y1="16" x2="6"  y2="24" stroke="white" strokeWidth="1.6" opacity=".7" />
          <line x1="16" y1="16" x2="26" y2="24" stroke="white" strokeWidth="1.6" opacity=".7" />
        </svg>
      </div>
      <span className="f-display" style={{ fontSize: s[1], fontWeight: 700, letterSpacing: '-.3px', lineHeight: 1, userSelect: 'none' }}>
        <span style={{ color: '#0099FF' }}>VELVO</span>
        <span style={{ color: '#FF7A00' }}>TIX</span>
      </span>
    </Link>
  );
}
